import { buildPortalView } from "./portal-view.mjs";

const CUSTOMER_VISIBLE_STATUS =
  "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

const OWNER_TASK_DUE_HOURS = {
  "Customer Success": 4,
  Support: 8,
  Finance: 24,
  "Executive Sponsor": 36
};

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  if (!request) {
    return buildPortalView(db);
  }

  db.workflow_state = db.workflow_state || [];
  db.owner_tasks = db.owner_tasks || [];
  db.customer_messages = db.customer_messages || [];
  db.audit_events = db.audit_events || [];

  const account = db.accounts.find((item) => item.account_id === request.account_id) || null;
  const contract = db.account_contracts.find((item) => item.account_id === request.account_id) || null;
  const contacts = db.contacts
    .filter((item) => item.account_id === request.account_id)
    .slice()
    .sort((a, b) => a.role.localeCompare(b.role) || a.contact_id.localeCompare(b.contact_id));
  const ownerGroups = db.workflow_request_owner_groups
    .filter((item) => item.request_id === request.request_id)
    .slice()
    .sort((a, b) => a.group_order - b.group_order);
  const riskSignals = db.workflow_request_risk_signals
    .filter((item) => item.request_id === request.request_id)
    .slice()
    .sort((a, b) => a.signal_order - b.signal_order);
  const activities = db.activities
    .filter((item) => item.account_id === request.account_id && item.subject_id === request.request_id)
    .slice()
    .sort((a, b) => new Date(a.occurred_at) - new Date(b.occurred_at));
  const ownerRouting = ownerGroups.map((item) => item.owner_group).join(" + ");
  const recoveryOwner = ownerGroups[ownerGroups.length - 1]?.owner_group || null;
  const timelineSummary = activities.map((item) => `${item.occurred_at} ${item.summary}`).join(" | ");

  replaceRows(db.workflow_state, request.request_id, [{
    workflow_state_id: `state-${request.request_id}`,
    request_id: request.request_id,
    task_id: request.task_id,
    account_id: request.account_id,
    title: request.title,
    status: request.expected_outcome,
    next_step: request.next_step,
    customer_message: request.customer_message,
    account_name: account?.name || null,
    account_tier: account?.tier || null,
    region: account?.region || null,
    contract_id: contract?.contract_id || null,
    renewal_date: contract?.renewal_date || null,
    support_plan: contract?.support_plan || null,
    arr_cents: contract?.arr_cents || null,
    contact_count: contacts.length,
    contact_roles: contacts.map((item) => item.role).join(", "),
    owner_routing: ownerRouting,
    recovery_owner: recoveryOwner,
    risk_signal_count: riskSignals.length,
    risk_signal_summary: riskSignals.map((item) => item.signal_name).join(", "),
    activity_count: activities.length,
    audit_timeline: timelineSummary,
    customer_visible_audit_history: true,
    opened_at: now,
    updated_at: now
  }]);

  replaceRows(db.owner_tasks, request.request_id, ownerGroups.map((group, index) => ({
    task_id: `task-${request.request_id}-${group.group_order}`,
    request_id: request.request_id,
    account_id: request.account_id,
    owner_group: group.owner_group,
    group_order: group.group_order,
    title: ownerTaskTitle(group.owner_group, request.title, account, contract),
    due_at: addHours(now, OWNER_TASK_DUE_HOURS[group.owner_group] ?? (index + 1) * 12),
    status: "open",
    created_at: now,
    updated_at: now
  })));

  replaceRows(db.customer_messages, request.request_id, [{
    message_id: `message-${request.request_id}`,
    request_id: request.request_id,
    account_id: request.account_id,
    channel: "portal",
    audience: "customer",
    customer_visible: true,
    body: request.customer_message,
    created_at: now,
    sent_at: now
  }]);

  replaceRows(db.audit_events, request.request_id, [
    ...activities.map((activity, index) => ({
      audit_event_id: `audit-${activity.activity_id}`,
      request_id: request.request_id,
      account_id: request.account_id,
      subject_id: request.request_id,
      activity_id: activity.activity_id,
